import React, { useEffect, useRef, useState } from "react";
import { ArrowRightToLine, Mountain, Eye, History, BookOpen, Archive, Shield, Users, Award } from "lucide-react";

// Paleta de colores corporativa
const COLORS = {
  primary: '#1a365d',      // Azul corporativo profundo
  secondary: '#2d3748',    // Gris azulado elegante
  accent: '#d4af37',       // Dorado patrimonial
  light: '#f7fafc',        // Fondo claro
  dark: '#1a202c',         // Texto principal
  muted: '#718096'         // Texto secundario
};

// Constantes de datos con identidad corporativa
const mainSections = [
  {
    id: "objective",
    title: "OBJETIVO",
    displayTitle: "Nuestro Objetivo",
    icon: ArrowRightToLine,
    body: ( 
      <div className="space-y-4">
        <p className="text-lg leading-relaxed">
          <strong className="text-[#d4af37]">Preservamos, organizamos y exhibimos</strong> el patrimonio corporativo de empresas bolivianas con más de 40 años de trayectoria. 
        </p>
        <ul className="space-y-2 text-[#2d3748]">
          <li className="flex items-start gap-2">
            <div className="w-2 h-2 bg-[#d4af37] rounded-full mt-2 flex-shrink-0"></div>
            <span>Digitalización de archivos históricos</span>
          </li>
          <li className="flex items-start gap-2">
            <div className="w-2 h-2 bg-[#d4af37] rounded-full mt-2 flex-shrink-0"></div>
            <span>Certificación de hitos empresariales</span>
          </li>
          <li className="flex items-start gap-2">
            <div className="w-2 h-2 bg-[#d4af37] rounded-full mt-2 flex-shrink-0"></div>
            <span>Narrativas vivas que inspiran futuras generaciones</span>
          </li>
        </ul>
      </div>
    ),
    image: '/media/historiapage/bolivia.jpg',
    stats: "400+ Empresas Documentadas"
  },
  {
    id: "mission",
    title: "MISIÓN",
    displayTitle: "Nuestra Misión",
    icon: Mountain,
    body: ( 
      <div className="space-y-4">
        <p className="text-lg leading-relaxed">
          <strong className="text-[#d4af37]">Proteger la memoria</strong> de la empresa boliviana mediante documentación rigurosa y diseño atemporal.
        </p>
        <div className="grid grid-cols-1 md:grid-cols-2 gap-4 mt-6">
          <div className="bg-[#f7fafc] p-4 rounded-lg border-l-4 border-[#d4af37]">
            <h4 className="font-semibold text-[#1a365d]">Documentación</h4>
            <p className="text-sm text-[#718096] mt-1">Rigurosa y verificable</p>
          </div>
          <div className="bg-[#f7fafc] p-4 rounded-lg border-l-4 border-[#1a365d]">
            <h4 className="font-semibold text-[#1a365d]">Preservación</h4>
            <p className="text-sm text-[#718096] mt-1">Diseño atemporal y duradero</p>
          </div>
        </div>
      </div>
    ),
    image: '/media/historiapage/AGRO.jpg',
    stats: "40+ Años de Trayectoria"
  },
  {
    id: "vision",
    title: "VISIÓN",
    displayTitle: "Nuestra Visión",
    icon: Eye,
    body: ( 
      <div className="space-y-4">
        <p className="text-lg leading-relaxed">
          Ser el <strong className="text-[#d4af37]">archivo nacional de referencia</strong> donde la historia de la excelencia empresarial sea atesorada.
        </p>
        <div className="bg-gradient-to-r from-[#1a365d] to-[#2d3748] p-6 rounded-lg text-white mt-6">
          <h4 className="font-semibold mb-2">Impacto Nacional</h4>
          <p className="text-sm opacity-90">Servimos como referencia para investigadores, emprendedores y familias que elevan el legado empresarial boliviano.</p>
        </div>
      </div>
    ),
    image: '/media/historiapage/flamingob.jpg',
    stats: "Referencia Nacional"
  },
  {
    id: "origin",
    title: "ORIGEN",
    displayTitle: "Nuestro Origen",
    icon: History,
    body: ( 
      <div className="space-y-4">
        <p className="text-lg leading-relaxed">
          Nacidos del <strong className="text-[#d4af37]">compromiso con la memoria cultural</strong>, uniendo a historiadores, archiveros e innovadores.
        </p>
        <blockquote className="border-l-4 border-[#d4af37] pl-4 italic text-[#2d3748] mt-4">
          "Si no documentamos nuestras empresas hoy, las generaciones futuras heredarán silencio donde debería haber legado."
        </blockquote>
      </div>
    ),
    image: '/media/historiapage/salarB.jpg',
    stats: "Desde 1980"
  },
];

const howItStartedSection = {
  id: "how",
  title: "NUESTRA HISTORIA",
  displayTitle: "Línea de Tiempo",
  icon: BookOpen,
  body: (
    <div className="w-full">
      <div className="relative py-8">
        {/* Línea de tiempo mejorada */}
        <div className="hidden md:block absolute left-1/2 top-20 transform -translate-x-1/2 w-4/5 h-1 bg-gradient-to-r from-[#d4af37] to-[#1a365d]" />
        
        <div className="grid grid-cols-1 md:grid-cols-4 gap-8 relative z-10">
          {[
            { 
              year: "1980s", 
              text: "Primeros archivos fundacionales recolectados",
              icon: Archive,
              highlight: true
            },
            { 
              year: "1990s", 
              text: "Alianzas público-privadas para preservación histórica",
              icon: Users,
              highlight: false
            },
            { 
              year: "2000s", 
              text: "Digitalización y estándares de certificación",
              icon: Shield,
              highlight: false
            },
            { 
              year: "Actualidad", 
              text: "Plataforma viva que conecta legado con innovación",
              icon: Award,
              highlight: true
            },
          ].map((m, index) => (
            <div key={m.year} className="text-center group">
              <div className={`relative mb-4 ${
                m.highlight ? 'scale-110' : 'scale-100'
              } transition-transform duration-300`}>
                {/* Punto de la línea de tiempo */}
                <div className={`w-6 h-6 rounded-full border-4 mx-auto mb-3 ${
                  m.highlight 
                    ? 'border-[#d4af37] bg-white shadow-lg' 
                    : 'border-[#1a365d] bg-white'
                }`} />
                
                {/* Icono */}
                <div className={`p-3 rounded-full mx-auto mb-3 ${
                  m.highlight 
                    ? 'bg-[#d4af37] text-white' 
                    : 'bg-[#1a365d] text-white'
                }`}>
                  <m.icon className="w-6 h-6 mx-auto" />
                </div>
              </div>
              
              <div className="bg-white rounded-lg p-4 shadow-md border border-gray-200 group-hover:shadow-lg transition-shadow duration-300">
                <span className="font-serif text-xl font-bold block mb-2 text-[#1a365d]">
                  {m.year}
                </span>
                <span className="block text-sm leading-tight text-[#718096]">
                  {m.text}
                </span>
              </div>
            </div>
          ))}
        </div>
      </div>
    </div>
  ),
};

// Estadísticas corporativas
const statsData = [
  { number: "40+", label: "Años de Experiencia" },
  { number: "500+", label: "Empresas Documentadas" },
  { number: "10K+", label: "Archivos Preservados" },
  { number: "100%", label: "Compromiso con Bolivia" }
];

// AÑADIR ESTA LÍNEA FALTANTE
const allSections = [...mainSections, howItStartedSection];

const AboutUsPage = () => {
  const [active, setActive] = useState(allSections[0].id);
  const [revealedSections, setRevealedSections] = useState({});
  const sectionRefs = useRef({});
  const [scrollY, setScrollY] = useState(0);

  // Efectos de scroll y observador
  useEffect(() => {
    const handleScroll = () => {
      setScrollY(window.scrollY);
    };
    
    window.addEventListener('scroll', handleScroll, { passive: true });
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  useEffect(() => {
    const observer = new IntersectionObserver(
      (entries) => {
        entries.forEach(entry => {
          if (entry.isIntersecting) {
            setActive(entry.target.id);
            setRevealedSections(prev => ({ ...prev, [entry.target.id]: true }));
          }
        });
      },
      { threshold: 0.3, rootMargin: "-10% 0px -10% 0px" }
    );

    allSections.forEach((s) => {
      const el = sectionRefs.current[s.id];
      if (el) observer.observe(el);
    });
    
    return () => observer.disconnect();
  }, []);

  const parallaxStyle = {
    transform: `translate3d(0, ${scrollY * 0.4}px, 0)`
  };

  return (
    <div className="min-h-screen bg-gradient-to-br from-[#f7fafc] to-[#edf2f7]">
      {/* HEADER CORPORATIVO */}
      <div className="h-[70vh] min-h-[600px] relative overflow-hidden">
        <div className="absolute inset-0" style={parallaxStyle}>
          <img 
            src="/media/historiapage/salarB.jpg"
            alt="Patrimonio Empresarial Boliviano"
            className="w-full h-full object-cover"
          />
          <div className="absolute inset-0 bg-gradient-to-r from-[#1a365d]/80 to-[#2d3748]/60"></div>
        </div>
        
        <div className="relative z-20 h-full flex items-center justify-center text-center text-white px-4">
          <div className="max-w-4xl">
            {/* Logo/sello visual */}
            <div className="mb-8">
              <div className="w-20 h-20 border-4 border-[#d4af37] rounded-full mx-auto mb-4 flex items-center justify-center">
                <Archive className="w-10 h-10 text-[#d4af37]" />
              </div>
            </div>
            
            <h1 className="font-playfair text-6xl lg:text-8xl font-normal mb-6 tracking-tight">
              Nosotros
            </h1>
            
            <div className="h-px w-32 bg-[#d4af37] mx-auto mb-6"></div>
            
            <h2 className="font-montserrat text-2xl lg:text-3xl font-light tracking-widest uppercase mb-6">
              Archivo Histórico Empresarial
            </h2>
            
            <p className="font-inter text-xl lg:text-2xl font-light leading-relaxed max-w-3xl mx-auto opacity-95">
              Custodios de la memoria corporativa boliviana, preservando legados que construyen futuro
            </p>
            
            {/* Elemento decorativo */}
            <div className="mt-12 flex justify-center">
              <div className="w-6 h-6 border-2 border-[#d4af37] rounded-full animate-bounce"></div>
            </div>
          </div>
        </div>
      </div>

      {/* ESTADÍSTICAS CORPORATIVAS */}
      <div className="relative z-10 -mt-20 px-4">
        <div className="max-w-6xl mx-auto">
          <div className="grid grid-cols-2 lg:grid-cols-4 gap-6">
            {statsData.map((stat, index) => (
              <div 
                key={index}
                className="bg-white rounded-2xl shadow-xl p-6 text-center border border-gray-100 transform hover:scale-105 transition-transform duration-300"
              >
                <div className="text-3xl lg:text-4xl font-bold text-[#1a365d] mb-2">
                  {stat.number}
                </div>
                <div className="text-sm text-[#718096] font-medium">
                  {stat.label}
                </div>
              </div>
            ))}
          </div>
        </div>
      </div>

      <main className="py-20 px-4">
        {/* SECCIONES PRINCIPALES */}
        <div className="max-w-6xl mx-auto space-y-16">
          {mainSections.map((s) => (
            <div
              key={s.id}
              id={s.id}
              ref={(el) => (sectionRefs.current[s.id] = el)}
              className={`
                scroll-mt-32 bg-white rounded-3xl shadow-2xl border border-gray-100 overflow-hidden
                transform transition-all duration-700 ease-out
                ${revealedSections[s.id] ? 'opacity-100 translate-y-0' : 'opacity-0 translate-y-12'}
              `}
            >
              <div className="flex flex-col lg:flex-row">
                {/* IMAGEN */}
                <div className="lg:w-2/5 relative overflow-hidden">
                  <img 
                    src={s.image} 
                    alt={s.displayTitle}
                    className="w-full h-80 lg:h-full object-cover transform hover:scale-110 transition-transform duration-700"
                  />
                  <div className="absolute bottom-4 left-4 bg-[#d4af37] text-white px-3 py-1 rounded-full text-sm font-medium">
                    {s.stats}
                  </div>
                </div>
                
                {/* CONTENIDO */}
                <div className="lg:w-3/5 p-8 lg:p-12">
                  <div className="flex items-center gap-4 mb-6">
                    <div className="p-3 bg-[#1a365d] rounded-xl">
                      <s.icon className="w-6 h-6 text-white" />
                    </div>
                    <h2 className="font-playfair text-4xl lg:text-5xl font-normal text-[#1a365d]">
                      {s.displayTitle}
                    </h2>
                  </div>
                  
                  <div className="h-px w-20 bg-[#d4af37] mb-8"></div>
                  
                  <div className="font-inter text-lg leading-relaxed text-[#2d3748]">
                    {s.body}
                  </div>
                </div>
              </div>
            </div>
          ))}
          
          {/* LÍNEA DE TIEMPO */}
          <div 
            id={howItStartedSection.id}
            ref={(el) => (sectionRefs.current[howItStartedSection.id] = el)}
            className={`
              scroll-mt-32 bg-white rounded-3xl shadow-2xl border border-gray-100 p-8 lg:p-12
              transform transition-all duration-700 ease-out
              ${revealedSections[howItStartedSection.id] ? 'opacity-100 translate-y-0' : 'opacity-0 translate-y-12'}
            `}
          >
            <div className="text-center mb-12">
              <div className="flex items-center justify-center gap-4 mb-6">
                <div className="p-3 bg-[#1a365d] rounded-xl">
                  <howItStartedSection.icon className="w-6 h-6 text-white" />
                </div>
                <h2 className="font-playfair text-4xl lg:text-5xl font-normal text-[#1a365d]">
                  {howItStartedSection.displayTitle}
                </h2>
              </div>
              <div className="h-px w-24 bg-[#d4af37] mx-auto"></div>
            </div>
            
            {howItStartedSection.body}
          </div>
        </div>
      </main>

      {/* FOOTER CORPORATIVO */}
      <footer className="bg-[#1a365d] text-white py-12">
        <div className="max-w-6xl mx-auto px-4 text-center">
          <div className="w-16 h-16 border-2 border-[#d4af37] rounded-full mx-auto mb-6 flex items-center justify-center">
            <Archive className="w-8 h-8 text-[#d4af37]" />
          </div>
          
          <h3 className="font-playfair text-2xl mb-4">Archivo Histórico Empresarial Boliviano</h3>
          
          <p className="text-gray-300 max-w-2xl mx-auto mb-6">
            Preservando la memoria, inspirando el futuro de la empresa boliviana
          </p>
          
          <div className="h-px w-20 bg-[#d4af37] mx-auto mb-6"></div>
          
          <p className="text-sm text-gray-400">
            © {new Date().getFullYear()} Archivo Histórico Empresarial Boliviano. Todos los derechos reservados.
          </p>
        </div>
      </footer>
    </div>
  );
};

export default AboutUsPage;
